=Generate a tomorrow outlook for topic '{{ $json.topic_slug }}' following {{ $json.date_key }}.

Today's summary:
Headline: {{ $json.summary.headline }}
Overview: {{ $json.summary.overview }}
Sentiment: {{ $json.summary.sentiment }}
Topic score: {{ $json.summary.topic_score }}/100

Key events:
{{ $json.summary.key_events.map((e, i) => {
  const srcs = Array.isArray(e.sources) && e.sources.length > 0
    ? ' [Sources: ' + e.sources.map(s => s.source_name).join(', ') + ']'
    : '';
  return `${i+1}. ${e.title} — ${e.significance}${srcs}`;
}).join('\n') }}

parameters.jsCode:
// Parse and validate the AI tomorrow outlook output.
const rawContent = $input.first().json?.message?.content
  || $input.first().json?.choices?.[0]?.message?.content
  || '';
const ctx = $('Execute Workflow Trigger').first().json;

let tomorrow_outlook;
try {
  const cleaned = rawContent.replace(/^```[a-z]*\n?|\n?```$/g, '').trim();
  tomorrow_outlook = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse tomorrow outlook JSON for ${ctx.topic_slug}/${ctx.date_key}: ${e.message}`);
}

// Validate required fields
if (!Array.isArray(tomorrow_outlook.key_watchpoints) || tomorrow_outlook.key_watchpoints.length === 0) {
  throw new Error('Tomorrow outlook missing key_watchpoints');
}
if (typeof tomorrow_outlook.outlook_summary !== 'string' || tomorrow_outlook.outlook_summary.length < 50) {
  throw new Error('Tomorrow outlook missing or too short outlook_summary');
}
if (!['low', 'medium', 'high'].includes(tomorrow_outlook.risk_level)) {
  tomorrow_outlook.risk_level = 'medium';
}

// Trim and clamp
tomorrow_outlook.key_watchpoints = tomorrow_outlook.key_watchpoints.slice(0, 5).map(w => ({
  title: String(w.title || '').slice(0, 100),
  description: String(w.description || '').slice(0, 300)
}));
tomorrow_outlook.scheduled_events = (tomorrow_outlook.scheduled_events || []).slice(0, 5).map(e => ({
  title: String(e.title || '').slice(0, 150),
  time_hint: e.time_hint ? String(e.time_hint).slice(0, 50) : null,
  impact: ['high', 'medium', 'low'].includes(e.impact) ? e.impact : 'medium'
}));
tomorrow_outlook.outlook_summary = String(tomorrow_outlook.outlook_summary).slice(0, 600);

return [{ json: { ...ctx, tomorrow_outlook } }];
